import{_ as e,o as a,c as l,a2 as r}from"./chunks/framework.BQ1gajhD.js";const f=JSON.parse('{"title":"地坛公园","description":"","frontmatter":{},"headers":[],"relativePath":"parks/ditan-park.md","filePath":"parks/ditan-park.md","lastUpdated":1784712887000}'),n={name:"parks/ditan-park.md"};function d(i,t,o,s,h,g){return a(),l("div",null,[...t[0]||(t[0]=[r('<h1 id="地坛公园" tabindex="-1">地坛公园 <a class="header-anchor" href="#地坛公园" aria-label="Permalink to &quot;地坛公园&quot;">​</a></h1><blockquote><p>&quot;明清祭地之所，银杏大道金黄。&quot;</p></blockquote><h2 id="简介" tabindex="-1">简介 <a class="header-anchor" href="#简介" aria-label="Permalink to &quot;简介&quot;">​</a></h2><p>地坛公园位于北京市东城区，是明清两代皇帝祭祀土地神的地方。地坛始建于明嘉靖九年（1530年），与天坛相对应，天坛祭天，地坛祭地。地坛公园以银杏大道闻名，每年秋季银杏叶黄，吸引大量游客。</p><h2 id="基本信息" tabindex="-1">基本信息 <a class="header-anchor" href="#基本信息" aria-label="Permalink to &quot;基本信息&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">项目</th><th style="text-align:left;">内容</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>开放时间</strong></td><td style="text-align:left;">6:00-21:30（旺季），6:00-20:30（淡季）</td></tr><tr><td style="text-align:left;"><strong>门票价格</strong></td><td style="text-align:left;">2元（皇祇室另收5元）</td></tr><tr><td style="text-align:left;"><strong>建议游玩</strong></td><td style="text-align:left;">1-2小时</td></tr><tr><td style="text-align:left;"><strong>最佳季节</strong></td><td style="text-align:left;">秋季银杏</td></tr><tr><td style="text-align:left;"><strong>交通方式</strong></td><td style="text-align:left;">地铁2号线/5号线雍和宫站</td></tr><tr><td style="text-align:left;"><strong>地址</strong></td><td style="text-align:left;">北京市东城区安定门外大街</td></tr></tbody></table><h2 id="历史沿革" tabindex="-1">历史沿革 <a class="header-anchor" href="#历史沿革" aria-label="Permalink to &quot;历史沿革&quot;">​</a></h2><h3 id="始建" tabindex="-1">始建 <a class="header-anchor" href="#始建" aria-label="Permalink to &quot;始建&quot;">​</a></h3><p>明嘉靖九年（1530年），明世宗朱厚熜决定实行天地分祀，在北京北郊建地坛，专祀土地神。</p><h3 id="清代修缮" tabindex="-1">清代修缮 <a class="header-anchor" href="#清代修缮" aria-label="Permalink to &quot;清代修缮&quot;">​</a></h3><p>清代，地坛多次修缮，规模不断扩大。乾隆年间，地坛达到鼎盛。</p><h3 id="民国荒废" tabindex="-1">民国荒废 <a class="header-anchor" href="#民国荒废" aria-label="Permalink to &quot;民国荒废&quot;">​</a></h3><p>民国时期，地坛逐渐荒废，成为乱葬岗。</p><h3 id="现代公园" tabindex="-1">现代公园 <a class="header-anchor" href="#现代公园" aria-label="Permalink to &quot;现代公园&quot;">​</a></h3><p>1957年，地坛辟为公园，对外开放。1984年，地坛被列为北京市文物保护单位。</p><h2 id="建筑特色" tabindex="-1">建筑特色 <a class="header-anchor" href="#建筑特色" aria-label="Permalink to &quot;建筑特色&quot;">​</a></h2><h3 id="方泽坛" tabindex="-1">方泽坛 <a class="header-anchor" href="#方泽坛" aria-label="Permalink to &quot;方泽坛&quot;">​</a></h3><p>方泽坛是地坛的核心建筑，是明清皇帝祭祀土地神的地方。</p><h4 id="布局" tabindex="-1">布局 <a class="header-anchor" href="#布局" aria-label="Permalink to &quot;布局&quot;">​</a></h4><ul><li><strong>坛台</strong>：方形，两层，象征&quot;地方&quot;</li><li><strong>坛墙</strong>：方形，四面</li><li><strong>泽门</strong>：坛南的正门</li></ul><h4 id="与天坛对比" tabindex="-1">与天坛对比 <a class="header-anchor" href="#与天坛对比" aria-label="Permalink to &quot;与天坛对比&quot;">​</a></h4><table tabindex="0"><thead><tr><th style="text-align:left;">对比项</th><th style="text-align:left;">天坛</th><th style="text-align:left;">地坛</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>形状</strong></td><td style="text-align:left;">圆形（天圆）</td><td style="text-align:left;">方形（地方）</td></tr><tr><td style="text-align:left;"><strong>颜色</strong></td><td style="text-align:left;">蓝色</td><td style="text-align:left;">黄色</td></tr><tr><td style="text-align:left;"><strong>层数</strong></td><td style="text-align:left;">三层</td><td style="text-align:left;">两层</td></tr><tr><td style="text-align:left;"><strong>祭祀对象</strong></td><td style="text-align:left;">天</td><td style="text-align:left;">地</td></tr></tbody></table><h3 id="皇祇室" tabindex="-1">皇祇室 <a class="header-anchor" href="#皇祇室" aria-label="Permalink to &quot;皇祇室&quot;">​</a></h3><p>皇祇室位于方泽坛南，是供奉土地神牌位的地方。</p><h3 id="斋宫" tabindex="-1">斋宫 <a class="header-anchor" href="#斋宫" aria-label="Permalink to &quot;斋宫&quot;">​</a></h3><p>斋宫是皇帝祭祀前斋戒的地方。</p><h3 id="银杏大道" tabindex="-1">银杏大道 <a class="header-anchor" href="#银杏大道" aria-label="Permalink to &quot;银杏大道&quot;">​</a></h3><p>地坛公园以银杏大道闻名，种植了大量银杏树。</p><h4 id="银杏树" tabindex="-1">银杏树 <a class="header-anchor" href="#银杏树" aria-label="Permalink to &quot;银杏树&quot;">​</a></h4><p>地坛公园的银杏树有近200株，是北京市区最大的银杏林之一。</p><h4 id="最佳观赏时间" tabindex="-1">最佳观赏时间 <a class="header-anchor" href="#最佳观赏时间" aria-label="Permalink to &quot;最佳观赏时间&quot;">​</a></h4><p>每年10月下旬至11月中旬，银杏叶黄，景色迷人。</p><h2 id="游览攻略" tabindex="-1">游览攻略 <a class="header-anchor" href="#游览攻略" aria-label="Permalink to &quot;游览攻略&quot;">​</a></h2><h3 id="推荐路线" tabindex="-1">推荐路线 <a class="header-anchor" href="#推荐路线" aria-label="Permalink to &quot;推荐路线&quot;">​</a></h3><p><strong>经典路线（约1-2小时）</strong>：</p><p>南门 → 方泽坛 → 皇祇室 → 银杏大道 → 斋宫 → 北门</p><p><strong>秋季路线（看银杏）</strong>：</p><p>西门 → 银杏大道 → 方泽坛 → 皇祇室 → 南门</p><h3 id="交通方式" tabindex="-1">交通方式 <a class="header-anchor" href="#交通方式" aria-label="Permalink to &quot;交通方式&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">方式</th><th style="text-align:left;">站点</th></tr></thead><tbody><tr><td style="text-align:left;">地铁</td><td style="text-align:left;">2号线/5号线雍和宫站A口</td></tr><tr><td style="text-align:left;">公交</td><td style="text-align:left;">18路、75路、108路等地坛西门站</td></tr><tr><td style="text-align:left;">步行</td><td style="text-align:left;">从雍和宫步行约10分钟</td></tr></tbody></table><h3 id="实用贴士" tabindex="-1">实用贴士 <a class="header-anchor" href="#实用贴士" aria-label="Permalink to &quot;实用贴士&quot;">​</a></h3><ol><li><strong>银杏最佳时间</strong>：10月下旬至11月中旬</li><li><strong>周末人多</strong>：周末人极多，建议工作日</li><li><strong>门票便宜</strong>：门票仅2元</li><li><strong>皇祇室另收</strong>：皇祇室另收5元</li><li><strong>结合游览</strong>：可与雍和宫、国子监一起游览</li><li><strong>拍照建议</strong>：早上8:00前或下午4:00后光线最佳</li></ol><h2 id="周边景点" tabindex="-1">周边景点 <a class="header-anchor" href="#周边景点" aria-label="Permalink to &quot;周边景点&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">景点</th><th style="text-align:center;">距离</th><th style="text-align:left;">特色</th></tr></thead><tbody><tr><td style="text-align:left;">雍和宫</td><td style="text-align:center;">步行5分钟</td><td style="text-align:left;">藏传佛教寺院</td></tr><tr><td style="text-align:left;">国子监</td><td style="text-align:center;">步行5分钟</td><td style="text-align:left;">古代最高学府</td></tr><tr><td style="text-align:left;">孔庙</td><td style="text-align:center;">步行5分钟</td><td style="text-align:left;">祭祀孔子的庙宇</td></tr><tr><td style="text-align:left;">簋街</td><td style="text-align:center;">步行10分钟</td><td style="text-align:left;">美食街</td></tr><tr><td style="text-align:left;">五道营胡同</td><td style="text-align:center;">步行10分钟</td><td style="text-align:left;">文艺胡同</td></tr></tbody></table><h2 id="文化价值" tabindex="-1">文化价值 <a class="header-anchor" href="#文化价值" aria-label="Permalink to &quot;文化价值&quot;">​</a></h2><p>地坛是全国重点文物保护单位，是中国古代&quot;天圆地方&quot;宇宙观的重要体现。</p><p>地坛与天坛相对应，体现了中国古代&quot;天圆地方&quot;&quot;天南地北&quot;的宇宙观念。</p><p>地坛的银杏大道是北京市区最美的秋景之一，每年吸引大量游客前来观赏。</p><hr><p><strong>📍 地址</strong>：北京市东城区安定门外大街 <strong>📞 电话</strong>：010-64214657</p>',50)])])}const b=e(n,[["render",d]]);export{f as __pageData,b as default};
